module top_module(
    output Z,
    input A,
    input B,
    input EN
);wire not_nand1;
    wire nand2_out;
    wire and_out;

    // Implement NAND1 gate
    assign not_nand1 = ~(A & B);

    // Implement NAND2 gate
    assign nand2_out = ~(not_nand1 & EN);

    // Implement AND gate
    assign and_out = A & B;

    // Implement final output
    assign Z = nand2_out & and_out;

endmodule
